export const getMarketData = async () => {
    // Simüle edilmiş canlı veriler (Altın, Dolar, Euro, Kripto)
    return [
        { symbol: 'ONS', price: '$2050', trend: 'up' },
        { symbol: 'USD/TRY', price: '₺32.40', trend: 'down' },
        { symbol: 'EUR/TRY', price: '₺35.10', trend: 'up' },
        { symbol: 'BTC', price: '$65000', trend: 'up' },
        { symbol: 'GRAM', price: '₺2150', trend: 'up' }
    ];
};
